const id = msg.req.query.id;
const chargerID = msg.req.query.chargerID || msg.req.query.charger_id;
const locationId = msg.req.query.locationId || msg.req.query.location_id;
const status = msg.req.query.status;

const allowedStatus = ["online", "offline"];
const conditions = [];

if (id !== undefined) {
    msg.topic = `SELECT charger_id AS id, name, chargerID, ocpi_last_update AS time, status, type, location_id AS locationId, max_session_time, num_connectors, description FROM ocpp_CSGO.Chargers WHERE charger_id = ?`;
    msg.payload = [id];
    msg.operation = 'GET';
    return msg;
}

if (chargerID !== undefined) {
    msg.topic = `SELECT charger_id AS id, name, chargerID, ocpi_last_update AS time, status, type, location_id AS locationId, max_session_time, num_connectors, description FROM ocpp_CSGO.Chargers WHERE chargerID = ?`;
    msg.payload = [chargerID];
    msg.operation = 'GET';
    return msg;
}

if (status) {
    if (!allowedStatus.includes(status)) {
        msg.statusCode = 400;
        msg.payload = { success: false, message: "Invalid status value. Allowed: online, offline" };
        return null;
    }
    conditions.push(`c.status = '${status}'`);
}

if (locationId) {
    conditions.push(`c.location_id = '${locationId}'`);
}

let whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

msg.topic = `SELECT c.charger_id AS id, c.name, c.chargerID, c.ocpi_last_update AS time, c.status, c.type, c.location_id AS locationId, c.max_session_time, c.num_connectors, c.description FROM ocpp_CSGO.Chargers c ${whereClause} ORDER BY c.ocpi_last_update DESC`;
msg.payload = [];
msg.operation = 'GET';
return msg;

if (msg.operation !== 'GET') {
    return null;
}

if (msg.error) {
    msg.statusCode = 500;
    msg.payload = { success: false, message: "Internal Server Error", details: msg.error.message };
    return msg;
}

if (!msg.payload || msg.payload.length === 0) {
    const id = msg.req.query.id || msg.req.query.chargerID || msg.req.query.charger_id;
    if (id !== undefined) {
        msg.statusCode = 404;
        msg.payload = { success: false, message: "Charger not found" };
        return msg;
    }
    msg.statusCode = 204;
    msg.payload = [];
    return msg;
}

const id = msg.req.query.id || msg.req.query.chargerID || msg.req.query.charger_id;
if (id !== undefined) {
    msg.statusCode = 200;
    msg.payload = { success: true, data: msg.payload[0] };
} else {
    msg.statusCode = 200;
    msg.payload = { success: true, count: msg.payload.length, data: msg.payload };
}
return msg;

const d = msg.payload || {};
if (!d.name || !d.type || !d.status) {
    msg.statusCode = 400;
    msg.payload = { success: false, message: "Missing required fields: name, type, status" };
    return null;
}

msg.topic = `INSERT INTO ocpp_CSGO.Chargers (name, type, status, location_id, max_session_time, num_connectors, description) VALUES (?, ?, ?, ?, ?, ?, ?)`;
msg.payload = [d.name, d.type, d.status, d.location_id || d.locationId || null, d.max_session_time || d.maxSessionTime || null, d.num_connectors || d.numConnectors || null, d.description || null];
msg.operation = 'POST';
return msg;

// Only process POST operations
if (msg.operation !== 'POST') {
    return null;
}

if (msg.error) {
    msg.statusCode = 500;
    msg.payload = { success: false, message: "Internal Server Error", details: msg.error.message };
    return msg;
}

msg.statusCode = 201;
msg.payload = { success: true, message: "Charger created successfully", insertId: msg.payload.insertId };
return msg;

const id = msg.req.query.id || msg.req.query.chargerID || msg.req.query.charger_id;
if (!id) {
    msg.statusCode = 400;
    msg.payload = { success: false, message: "Charger ID is required (use ?id={id} or ?chargerID={id} or ?charger_id={id})" };
    return null;
}

const d = msg.payload || {};
if (!d.name || !d.type || !d.status) {
    msg.statusCode = 400;
    msg.payload = { success: false, message: "Missing required fields: name, type, status" };
    return null;
}

// Determine which field to use for WHERE clause
let whereField = 'charger_id';
if (msg.req.query.chargerID || msg.req.query.charger_id) {
    whereField = 'chargerID';
}

msg.topic = `UPDATE ocpp_CSGO.Chargers SET name=?, type=?, status=?, location_id=?, max_session_time=?, num_connectors=?, description=? WHERE ${whereField}=?`;
msg.payload = [d.name, d.type, d.status, d.location_id || d.locationId || null, d.max_session_time || d.maxSessionTime || null, d.num_connectors || d.numConnectors || null, d.description || null, id];
msg.operation = 'PUT';
msg.chargerId = id;
return msg;

// Only process PUT operations
if (msg.operation !== 'PUT') {
    return null;
}

if (msg.error) {
    msg.statusCode = 500;
    msg.payload = { success: false, message: "Internal Server Error", details: msg.error.message };
    return msg;
}

if (msg.payload.affectedRows === 0) {
    msg.statusCode = 404;
    msg.payload = { success: false, message: "Charger not found" };
    return msg;
}

msg.statusCode = 200;
msg.payload = { success: true, message: "Charger updated successfully" };
return msg;

const id = msg.req.query.id || msg.req.query.chargerID || msg.req.query.charger_id;
if (!id) {
    msg.statusCode = 400;
    msg.payload = { success: false, message: "Charger ID is required (use ?id={id} or ?chargerID={id} or ?charger_id={id})" };
    return null;
}

// Determine which field to use for WHERE clause
let whereField = 'charger_id';
if (msg.req.query.chargerID || msg.req.query.charger_id) {
    whereField = 'chargerID';
}

msg.topic = `SELECT COUNT(*) as count FROM ocpp_CSGO.Connectors WHERE charger_id = ?`;
msg.payload = [id];
msg.checkConnectors = true;
msg.operation = 'DELETE_CHECK';
msg.chargerId = id;
msg.whereField = whereField;
return msg;

// Only process DELETE operations
if (msg.operation !== 'DELETE' && msg.operation !== 'DELETE_CHECK') {
    return null;
}

const id = msg.chargerId || msg.req?.query?.id || msg.req?.query?.chargerID || msg.req?.query?.charger_id;
const whereField = msg.whereField || 'charger_id';

if (msg.checkConnectors) {
    const count = msg.payload && msg.payload[0] ? msg.payload[0].count : 0;
    if (count > 0) {
        msg.statusCode = 400;
        msg.payload = { success: false, message: `Cannot delete charger. It has ${count} connector(s) associated with it.` };
        return msg;
    }
    msg.topic = `DELETE FROM ocpp_CSGO.Chargers WHERE ${whereField} = ?`;
    msg.payload = [id];
    msg.checkConnectors = false;
    msg.operation = 'DELETE';
    msg.chargerId = id;
    msg.whereField = whereField;

    // Send back to MySQL node via output 2
    return [null, msg];
}

if (msg.error) {
    msg.statusCode = 500;
    msg.payload = { success: false, message: "Internal Server Error", details: msg.error.message };
    return msg;
}

if (msg.payload.affectedRows === 0) {
    msg.statusCode = 404;
    msg.payload = { success: false, message: "Charger not found" };
    return msg;
}

msg.statusCode = 200;
msg.payload = { success: true, message: "Charger deleted successfully" };
return msg;

msg.statusCode = 500;
msg.payload = { success: false, message: "Internal Server Error", details: msg.error ? msg.error.message : "Unknown error" };
return msg;
